"""
MKT Christ Commentary — Psalm 139 (24 verses — divine omniscience and omnipresence)
Run: python3 scripts/zc-christ-psalm-139.py
Key decisions:
- v1 'searched me and know me' → John 2:25 Christ knew what was in each person;
  Heb 4:13 all laid bare before him
- v5 'surround me on every side / laid your hand upon me' → Matt 28:20 'I am
  with you always'; the omnipresence of YHWH is the omnipresence of Christ
- v7-10 nowhere-to-flee-from-presence → Rom 8:38-39 nothing separates from
  love of God in Christ — the inescapable presence becomes inseparable love
- v11-12 darkness-not-dark-to-you → John 1:5 light shines in darkness; Christ
  the light that darkness cannot overcome
- v13-14 formed-in-womb / fearfully-wonderfully-made → Heb 2:14 Incarnation:
  Christ himself is formed in a womb, affirming the dignity of every human life
- v16 days-written-before-existence → Eph 1:4-5 chosen in Christ before creation;
  Acts 2:23 Christ's death foreknown by God's deliberate plan
- v18 'when I wake I am still with you' → resurrection morning; the waking
  presence is the presence of the risen Christ with his people
- v23-24 'search me and know my heart' → Heb 4:15 Christ without sin;
  the prayer is enabled by his perfect transparency before the Father
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys — safe to re-run after manual edits.
    # CHANGE? If psalms.json schema changes, update merge_comm and PSALMS below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   psalms.json')); print('139 v16:',d.get('139',{}).get('16','MISSING')[:60])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


PSALMS = {
    "139": {
        "1": "<p>\"O LORD, you have <strong>searched me</strong> and you know me\" — the great psalm of divine omniscience opens with the most intimate claim: God knows the psalmist exhaustively. John 2:25: Christ \"did not need any testimony about mankind, for <strong>he knew what was in each person</strong>.\" Hebrews 4:13: \"Nothing in all creation is hidden from God's sight. Everything is uncovered and laid bare before the eyes of him to whom we must give account.\" The divine knowing of Psalm 139:1 is the omniscience of Christ — the one who searches and knows every human being as only the Creator can. This knowing is not surveillance but intimate love: the God who knows everything about us is the God who still comes to redeem us.</p>",
        "2": "<p>\"You know when I sit and when I stand; you understand my thoughts before I even form them\" — the divine knowledge of every posture and every thought before it surfaces. Hebrews 4:15: Christ \"has been tempted in every way, just as we are — yet he did not sin.\" The Son who knows human experience from within — sitting, standing, the forming thought — is the High Priest whose empathetic knowledge enables his perfect intercession. John 10:14-15: \"I know my sheep and my sheep know me — just as the Father knows me and I know the Father.\" The mutual knowing between shepherd and sheep is the knowing of Psalm 139:2 taken to its incarnate depth.</p>",
        "3": "<p>\"You trace every path I walk and every place I rest; you are familiar with all my ways\" — the divine tracking of every movement and resting place. Matthew 28:20: \"I am with you always, to the very end of the age.\" The omnipresence of YHWH that traces every path in Psalm 139:3 is the permanent presence Christ promises his disciples — he is with them on every road (Luke 24:15: \"Jesus himself came up and walked along with them\"), in every resting place, along every way. The Emmaus road is Psalm 139:3 enacted: the risen Lord traces the path of the despairing disciples.</p>",
        "4": "<p>\"Before a word is on my tongue, you know it completely, O LORD\" — the divine foreknowledge of every word. John 10:3: \"He calls his own sheep by name.\" Christ knows each person's words before they speak them — John 4:17-18 (the Samaritan woman: \"You are right when you say you have no husband\"); John 21:18 (foretelling Peter's death). The foreknowledge of Psalm 139:4 is the intimate divine knowing that the Incarnate Son exercises with perfect compassion — he knows the word before it is spoken and meets the person exactly where they are.</p>",
        "5": "<p>\"You surround me on every side — behind and before — and you have laid your hand upon me\" — the divine encompassing: no side unguarded, the hand resting on the psalmist. Matthew 28:20: \"I am with you <strong>always</strong>, to the very end of the age.\" John 10:28-29: \"No one will snatch them out of my hand... No one can snatch them out of my Father's hand.\" The surrounding-on-every-side of Psalm 139:5 is the double security of Christ's and the Father's hand — the believer is encircled by the divine presence that neither enemy assault nor inner failure can penetrate.</p>",
        "6": "<p>\"This knowledge is beyond me — too wonderful, too high for me to grasp\" — the worshipful response to the incomprehensible divine knowing. Ephesians 3:18-19: Paul prays that the community may \"grasp how wide and long and high and deep is the love of Christ, and to know this love that surpasses knowledge.\" The too-wonderful-to-grasp knowledge of Psalm 139:6 is the love of Christ — the very love that the psalmist glimpses in the divine omniscience is the love that overflows all comprehension. To be fully known by God is to be fully loved by him — and that love, in Christ, is beyond all measuring.</p>",
        "7": "<p>\"Where can I go to escape your Spirit? Where can I flee from your presence?\" — the impossibility of escaping the divine presence. Romans 8:38-39: \"neither death nor life, neither angels nor demons, neither the present nor the future, nor any powers, neither height nor depth, nor <strong>anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord</strong>.\" The inescapability of YHWH's presence in Psalm 139:7 is the inseparability of Christ's love in Romans 8 — the same comprehensive reach, but transformed from the framing of 'nowhere to flee' into 'nothing can separate.' The divine omnipresence becomes the Christian's greatest comfort through the Incarnation and resurrection of Christ.</p>",
        "8": "<p>\"If I rise to heaven, you are there; if I make my bed in the grave (<em>sheol</em>), you are there too\" — the vertical axis of divine presence: highest height and deepest depth. Philippians 2:10: \"at the name of Jesus every knee should bow, in <strong>heaven and on earth and under the earth</strong>.\" Christ's presence spans the same vertical axis — he ascends to the highest (Eph 4:10: \"above all the heavens\") and descends to the lowest (Eph 4:9: \"he also descended to the lower, earthly regions\"). The heaven-Sheol axis of Psalm 139:8 is crossed by Christ himself in his incarnation, death, and resurrection — he is present in both extremes because he has traveled them both.</p>",
        "9": "<p>\"If I fly away on the wings of the dawn and settle at the farthest edge of the sea\" — the horizontal axis of divine presence: east to west. Matthew 28:19-20: \"Go and make disciples of <strong>all nations</strong>... I am with you always.\" The geographic omnipresence of Psalm 139:9 becomes the Great Commission: Christ's presence accompanies his disciples to the farthest edge of the sea, which is why they can go there. Acts 1:8: \"you will be my witnesses in Jerusalem... and to the ends of the earth.\" The wings-of-the-dawn reach of YHWH's presence is the apostolic reach of Christ's mission.</p>",
        "10": "<p>\"even there your hand will guide me, and your right hand will hold me fast\" — the guiding and holding hand at the farthest edge of creation. John 10:28-29: \"I give them eternal life, and they shall never perish; no one will snatch them out of my hand... No one can snatch them out of my Father's hand.\" The right hand that holds fast in Psalm 139:10 is the double grip of Father and Son — the divine holding that operates at the farthest reaches of geography and the deepest reaches of experience, because neither distance nor suffering can loosen the grasp.</p>",
        "11": "<p>\"If I say, 'The darkness will surely hide me, and the light around me turn to night'\" — the hypothetical attempt to hide in darkness. John 1:5: \"The light shines in the darkness, and the darkness has not overcome it.\" John 3:19: \"Light has come into the world, but people loved darkness instead of light.\" The attempt to flee into darkness that Psalm 139:11 imagines is the condition of those who prefer darkness — but even that preference is known fully by the God who sees in the dark. Christ as the light exposes and redeems even the deliberate hiding, not to condemn but to save (John 3:17).</p>",
        "12": "<p>\"even the darkness is not dark to you; the night shines like the day, for darkness and light are the same to you\" — the equalizing of darkness and light before the divine sight. John 1:4-5: \"In him was life, and that life was the light of all mankind. The light shines in the darkness, and the darkness has not overcome it.\" Christ is the light that cannot be overcome by any darkness — the darkness that is not dark to God becomes the darkness that cannot overcome the light in Christ. Resurrection morning (John 20:1: \"Early on the first day of the week, while it was still dark\") is Psalm 139:12 enacted: even in the pre-dawn dark, the light is already present.</p>",
        "13": "<p>\"For you formed my inward parts (<em>kilayot</em>); you wove me together in my mother's womb\" — the divine fashioning of the person from conception. Hebrews 2:14: \"Since the children have flesh and blood, he too <strong>shared in their humanity</strong>.\" Luke 1:35: \"The Holy Spirit will come on you, and the power of the Most High will overshadow you. So the holy one to be born will be called the Son of God.\" Christ himself is formed and woven in a mother's womb — the Creator of Psalm 139:13 submits to being created, affirming from the inside the sacred dignity of every human life from its most hidden beginning. The Incarnation is the ultimate endorsement of what the psalmist celebrates: the womb is where God works.</p>",
        "14": "<p>\"I praise you because I am <strong>fearfully and wonderfully made</strong> — your works are marvellous, and my whole being knows it\" — the doxology of creaturely dignity. Hebrews 2:14-15: \"Since the children have flesh and blood, he too shared in their humanity so that by his death he might break the power of him who holds the power of death.\" Christ takes on the fearfully-and-wonderfully-made human body — he redeems it, raises it, and ascends in it. The resurrection of Christ is the redemption of the fearfully-and-wonderfully-made body: human embodiment is so valued by God that the Son takes it on permanently, never to lay it aside (Acts 1:9-11; Rev 5:6).</p>",
        "15": "<p>\"My very frame was not hidden from you when I was made in secret, skillfully crafted in the depths of the earth\" — the hidden formation, known entirely by God. Colossians 1:26-27: \"the mystery that has been kept hidden for ages and generations, but is now disclosed to the Lord's people... Christ in you, the hope of glory.\" The hiddenness-made-known of Psalm 139:15 is the pattern of the gospel: what was hidden (the eternal purpose of God in Christ) is now revealed. Christ himself was \"hidden\" from the powers (1 Cor 2:8: \"None of the rulers of this age understood it\") until the resurrection disclosed what had been skillfully crafted in the hidden counsel of God.</p>",
        "16": "<p>\"Your eyes saw my unformed body; all my days were <strong>written in your book</strong> before any of them had come to be\" — the divine foreknowledge of every day before it is lived. Ephesians 1:4-5: \"he <strong>chose us in him before the creation of the world</strong>... he predestined us for adoption to sonship through Jesus Christ.\" Acts 2:23: \"This man was handed over to you by God's <strong>deliberate plan and foreknowledge</strong>.\" The days written in the book before they exist include Christ's own incarnation, atoning death, and resurrection — all was written in the divine counsel before time. And it includes the election of every believer in Christ, chosen before the foundation of the world (Eph 1:4).</p>",
        "17": "<p>\"How priceless are your thoughts toward me, O God! How immeasurable their total!\" — the overwhelming quantity of divine attention to each person. Romans 8:26-27: \"the Spirit intercedes for God's people in accordance with the will of God.\" Hebrews 7:25: Christ \"always lives to make intercession\" for those who come to God through him. The innumerable divine thoughts toward each person are expressed through the unceasing intercession of the Son and the Spirit — the thought-count of Psalm 139:17 is the intercession-count of the Trinitarian God who never stops attending to each of his own.</p>",
        "18": "<p>\"If I tried to count them, they would be more than the grains of sand; and <strong>when I wake, I am still with you</strong>\" — the persistence of divine presence even through sleep and waking. The final phrase is resurrection language: \"when I wake\" from the death that is sleep, the divine presence is there. Acts 2:27 (quoting Ps 16:10): \"you will not abandon me to the realm of the dead.\" The waking of Psalm 139:18 is the Easter morning waking of Christ — rising from the death-sleep into the permanent presence of the Father. And for every believer: 1 Thessalonians 5:10: \"He died for us so that, whether we are awake or asleep, we may live together with him.\"</p>",
        "19": "<p>\"O God, if only you would put an end to the wicked! Get away from me, you murderers!\" — the sudden shift from meditation to imprecation: the one who knows divine omniscience calls on God for justice. Second Thessalonians 1:6-8: \"God is just: He will pay back trouble to those who trouble you... when the Lord Jesus is revealed from heaven in blazing fire with his powerful angels. He will punish those who do not know God.\" Christ is the eschatological judge who will put an end to the wicked — not through the psalmist's impetuous cry but through the sovereign judgment of the last day. The prayer of Psalm 139:19 is handed up to the one who alone can execute it justly.</p>",
        "20": "<p>\"They speak against you with evil intent; your adversaries invoke your name for nothing\" — the blasphemers who misuse the divine name. Matthew 27:39-44: the crowds, rulers, and criminals at the cross mock Jesus — \"He trusts in God. Let God rescue him now if he wants him, for he said, 'I am the Son of God.'\" The adversaries who invoke the divine name for nothing in Psalm 139:20 are those who twist it into a weapon of mockery at Calvary. Christ absorbs the blasphemy; the resurrection vindicates the name and exposes the adversaries' futility.</p>",
        "21": "<p>\"LORD, don't I hate those who hate you? Don't I despise those who rise up against you?\" — the alignment of the psalmist's loves and hates with God's. Hebrews 1:9 (quoting Ps 45:7): \"You have loved righteousness and <strong>hated wickedness</strong>.\" Christ, the perfectly holy one, hates what God hates and loves what God loves — his hatred of wickedness is what drives the temple cleansing (John 2:13-17) and the woes against hypocrisy (Matt 23). The alignment with divine loves and hates is most perfectly embodied in Christ and most imperfectly approximated by believers who are being conformed to his image.</p>",
        "22": "<p>\"I hate them with an absolute hatred; I number them among my enemies\" — the total, comprehensive nature of the alignment. This is the psalmist's way of expressing undivided loyalty to YHWH — there is no middle ground, no partial allegiance to what opposes God. Matthew 6:24: \"No one can serve two masters.\" James 4:4: \"friendship with the world means enmity against God.\" Christ models the absolute commitment the psalm describes: at Gethsemane he chooses the Father's will absolutely, with no equivocation — the absolute hatred of what opposes God is the flip side of the absolute love for the Father that drives the cross.</p>",
        "23": "<p>\"Search me, O God, and know my heart; put me to the test and see what I am thinking\" — the prayer for divine examination, inviting the very scrutiny the psalm has described. Hebrews 4:15: \"we have one who has been tempted in every way, just as we are — <strong>yet he did not sin</strong>.\" Christ is the one who could pray Psalm 139:23 with complete openness — no hidden sinful path, no double thought to conceal. His perfect transparency before the Father is what he now enables in his people: because he bears their sins, they can invite divine examination without terror, trusting his righteousness to cover what the examination finds.</p>",
        "24": "<p>\"See if there is any harmful path in me, and <strong>lead me in the way that lasts forever</strong>\" — the concluding prayer: remove the wrong way, establish the eternal way. John 14:6: \"I am the <strong>way</strong> and the truth and the life.\" First John 1:9: \"If we confess our sins, he is faithful and just and will forgive us our sins and purify us from all unrighteousness.\" The prayer for the harmful path to be removed is answered by confession enabled by Christ's atoning work; the prayer to be led in the way that lasts forever is answered by Christ himself, who is that Way — the eternal path that leads to the Father, now and in the age to come.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "psalms")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, PSALMS)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "psalms", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("1", "knew"), ("7", "separate"), ("13", "womb"), ("16", "foreknowledge"), ("24", "way")]:
        entry = existing.get("139", {}).get(v, "MISSING")
        print(f"  Ps 139:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")


if __name__ == "__main__":
    main()
